mapper.select:
SELECT
survey_response_draft_id as surveyResponseDraftId,
survey_instance_id as surveyInstanceId,
question_id as questionId,
responder_user_id as responderUserId,
answer_value as answerValue
FROM survey_response_drafts
WHERE company_id = #{companyId,jdbcType=VARCHAR}
AND survey_instance_id = #{instanceId,jdbcType=VARCHAR}
AND responder_user_id = #{responderUserId,jdbcType=VARCHAR}

mapper.delete:
